function formatTime(date) {
  const hours = String(date.getHours()).padStart(2, "0");
  const minutes = String(date.getMinutes()).padStart(2, "0");
  const seconds = String(date.getSeconds()).padStart(2, "0");
  return `${hours}:${minutes}:${seconds}`;
}

function synchronousFunction() {
  const start = new Date();
  console.log("Starting function execution at", formatTime(start));

  // This will block JavaScript execution for exactly 3 seconds
  while (Date.now() - start.getTime() < 3000) {
    // JavaScript is completely blocked during this time
    // No other code can run until this loop finishes
  }

  const end = new Date();
  console.log("Function execution completed at", formatTime(end));
}

