  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  // Task: Create a ref to store the AbortController instance called abortControllerRef using the useRef hook

  useEffect(() => {
    const fetchData = async () => {
      setTodo(null);
      setIsLoading(true);
      setError(null);

      // Task: Create a new AbortController instance and assign it to the abortControllerRef.current variable

      try {
        const response = await fetch(API_URL, {
          // Task: Pass the abortControllerRef.current.signal to the signal property of the fetch request options to make it cancellable
        });

        if (!response.ok) {
          throw new Error(
            `Server error: ${response.status} ${response.statusText}`,
          );
        }

        const data = await response.json();
        setTodo(data);
      } catch (e) {
        // Task: Check if the error is an AbortError using e.name === "AbortError" and if so, return early

        setError(e.message);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();

    // Task: Return a cleanup function that calls abortControllerRef.current.abort() to cancel the request when the component unmounts
  }, []);

