# use-context-selector

React useContextSelector hook in userland

## Introduction

React Context and useContext is often used to avoid prop drilling,
however it's known that there's a performance issue.
When a context value is changed, all components that useContext
will re-render.

## Usage

```javascript
import { useState } from "react";
import { createRoot } from "react-dom/client";

import { createContext, useContextSelector } from "use-context-selector";

const context = createContext(null);

const Counter1 = () => {
  const count1 = useContextSelector(context, (v) => v[0].count1);
  const setState = useContextSelector(context, (v) => v[1]);
  const increment = () =>
    setState((s) => ({
      ...s,
      count1: s.count1 + 1,
    }));
  return (
    <div>
      <span>Count1: {count1}</span>
      <button type="button" onClick={increment}>
        +1
      </button>
      {Math.random()}
    </div>
  );
};

const Counter2 = () => {
  const count2 = useContextSelector(context, (v) => v[0].count2);
  const setState = useContextSelector(context, (v) => v[1]);
  const increment = () =>
    setState((s) => ({
      ...s,
      count2: s.count2 + 1,
    }));
  return (
    <div>
      <span>Count2: {count2}</span>
      <button type="button" onClick={increment}>
        +1
      </button>
      {Math.random()}
    </div>
  );
};

const StateProvider = ({ children }) => (
  <context.Provider value={useState({ count1: 0, count2: 0 })}>
    {children}
  </context.Provider>
);

const App = () => (
  <StateProvider>
    <Counter1 />
    <Counter2 />
  </StateProvider>
);

createRoot(document.getElementById("app")).render(<App />);
```

## API

<!-- Generated by documentation.js. Update this documentation by updating the source code. -->

### createContext

This creates a special context for `useContextSelector`.

#### Parameters

- `defaultValue` **Value**&#x20;

#### Examples

```javascript
import { createContext } from "use-context-selector";

const PersonContext = createContext({ firstName: "", familyName: "" });
```

### useContextSelector

This hook returns context selected value by selector.

It will only accept context created by `createContext`.
It will trigger re-render if only the selected value is referentially changed.

The selector should return referentially equal result for same input for better performance.

#### Parameters

- `context` **Context\<Value>**&#x20;
- `selector` **function (value: Value): Selected**&#x20;

#### Examples

```javascript
import { useContextSelector } from "use-context-selector";

const firstName = useContextSelector(PersonContext, (state) => state.firstName);
```

### useContext

This hook returns the entire context value.
Use this instead of React.useContext for consistent behavior.

#### Parameters

- `context` **Context\<Value>**&#x20;

#### Examples

```javascript
import { useContext } from "use-context-selector";

const person = useContext(PersonContext);
```

### useContextUpdate

This hook returns an update function to wrap an updating function

Use this for a function that will change a value in
concurrent rendering in React 18.
Otherwise, there's no need to use this hook.

#### Parameters

- `context` **Context\<Value>**&#x20;

#### Examples

```javascript
import { useContextUpdate } from 'use-context-selector';

const update = useContextUpdate();

// Wrap set state function
update(() => setState(...));

// Experimental suspense mode
update(() => setState(...), { suspense: true });
```

App.jsx.code:
import { useState, useEffect } from "react";
import {
  createContext,
  useContext,
  useContextSelector,
} from "use-context-selector";

const AppContext = createContext();

function NameComponent() {
  // Task: Replace the useContext hook with useContextSelector and select only the name using a selector function
  const { name } = useContext(AppContext);

  // Use to keep track of how many times the component is rendered
  useEffect(() => {
    console.log("NameComponent rendered");
  });

  return <p>Name: {name}</p>;
}

function CountComponent() {
  // Task: Replace the useContext hook with useContextSelector and select only the count using a selector function
  const { count } = useContext(AppContext);

  // Use to keep track of how many times the component is rendered
  useEffect(() => {
    console.log("CountComponent rendered");
  });

  return <p>Count: {count}</p>;
}

function AppProvider({ children }) {
  const [name, setName] = useState("John");
  const [count, setCount] = useState(0);

  return (
    <AppContext.Provider value={{ name, count }}>
      <div>
        <h1>Context Selector</h1>

        <button onClick={() => setName(name === "John" ? "Jane" : "John")}>
          Change Name
        </button>
        <button onClick={() => setCount(count + 1)}>Increment Count</button>

        {children}
      </div>
    </AppContext.Provider>
  );
}

function App() {
  return (
    <AppProvider>
      <NameComponent />
      <CountComponent />
    </AppProvider>
  );
}

export default App;

