import { useState, useOptimistic, useTransition } from "react";

// Mock async function
async function saveTodo(todo) {
  await new Promise((resolve) => setTimeout(resolve, 1000));
  return todo;
}

function App() {
  const [todos, setTodos] = useState(["Learn React", "Build an app"]);
  const [newTodo, setNewTodo] = useState("");

  const [isPending, startTransition] = useTransition();

  // Task: Use useOptimistic to create optimistic todos state
  // Pass the todos state as the first argument
  // Pass a state updater function that receives the previous state and returns the new state as the second argument
  // The state updater function should return the new state with the new todo added at the end of the array

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!newTodo.trim()) return;

    startTransition(async () => {
      // Task: Add the new todo optimistically when the form is submitted inside startTransition

      try {
        await saveTodo(newTodo);

        startTransition(() => {
          setTodos((prev) => [...prev, newTodo]);
          setNewTodo("");
        });
      } catch (error) {
        console.error("Failed to save todo");
      }
    });
  };

  return (
    <div>
      <h1>Optimistic UI Updates</h1>

      <form onSubmit={handleSubmit}>
        <input
          type="text"
          disabled={isPending}
          value={newTodo}
          onChange={(e) => setNewTodo(e.target.value)}
          placeholder="Add a todo..."
        />
        <button type="submit">Add</button>
      </form>

      <ul>
        {/* Render the optimistic state using optimisticTodos instead of todos */}
        {todos.map((todo, index) => (
          <li key={index}>{todo}</li>
        ))}
      </ul>
    </div>
  );
}

