export const fetchLargeData = async ({ signal }) => {
  console.log("API call: starting large data fetch (5 seconds)");

  try {
    await new Promise((resolve, reject) => {
      const timeoutId = setTimeout(resolve, 5000);

      signal?.addEventListener("abort", () => {
        clearTimeout(timeoutId);
        reject(new Error("Request was cancelled"));
      });
    });

    console.log("API call: large data fetch completed");
    return {
      id: 1,
      data: "This is some large data that took 5 seconds to fetch",
      timestamp: new Date().toISOString(),
    };
  } catch (error) {
    console.log("API call: fetch was cancelled or failed");
    throw error;
  }
};

