  return (
    <div>
      <h3>User Name Component (Renders: {renderCount.current})</h3>
      <p>Name: {userName}</p>
    </div>
  );
}

function FullUserData() {
  // Used to keep track of how many times the component is rendered
  const renderCount = useRef(0);
  renderCount.current += 1;

  const { data: user } = useQuery({
    queryKey: ["user"],
    queryFn: fetchUser,
  });

  return (
    <div>
      <h3>Full User Data Component (Renders: {renderCount.current})</h3>
      <p>Name: {user?.name}</p>
      <p>Email: {user?.email}</p>
      <p>Role: {user?.role}</p>
      <p>Last Active: {user?.lastActive}</p>
    </div>
  );
}

function App() {
  const queryClient = useQueryClient();

  return (
    <div>
      <h1>Performance Optimization</h1>
      <p>
        Watch the render counts to see how select prevents unnecessary
        re-renders!
      </p>

      <button
        onClick={() => queryClient.invalidateQueries({ queryKey: ["user"] })}
      >
        Refresh User
      </button>

      <UserName />
      <FullUserData />
    </div>
  );
}

export default App;

