  name: "Alice Johnson",
  email: "alice@example.com",
  role: "Developer",
  lastActive: new Date().toISOString(),
};

let postsData = [
  { id: 1, title: "First Post", content: "Content 1", likes: 5 },
  { id: 2, title: "Second Post", content: "Content 2", likes: 12 },
  { id: 3, title: "Third Post", content: "Content 3", likes: 8 },
];

export const fetchUser = async () => {
  console.log("API call: fetching user");
  await new Promise((resolve) => setTimeout(resolve, 1000));

  // Update lastActive to simulate changing data
  userData.lastActive = new Date().toISOString();
  return { ...userData };
};

export const fetchPosts = async () => {
  console.log("API call: fetching posts");
  await new Promise((resolve) => setTimeout(resolve, 800));

  // Randomly update likes to simulate changing data
  postsData = postsData.map((post) => ({
    ...post,
    likes: post.likes + Math.floor(Math.random() * 3),
  }));

  return [...postsData];
};

